def pacificAtlantic(heights):
    if not heights:
        return []
    m, n = len(heights), len(heights[0])
    pac, atl = set(), set()
    def dfs(i, j, visited):
        visited.add((i, j))
        for x, y in [(i+1,j),(i-1,j),(i,j+1),(i,j-1)]:
            if 0 <= x < m and 0 <= y < n and (x,y) not in visited and heights[x][y] >= heights[i][j]:
                dfs(x, y, visited)
    for i in range(m):
        dfs(i, 0, pac)
        dfs(i, n-1, atl)
    for j in range(n):
        dfs(0, j, pac)
        dfs(m-1, j, atl)
    return list(pac & atl)

